module.render:
const esc = (s) => String(s).replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;');
const kind = (args.kind || 'theorem').toLowerCase();
const name = kind.charAt(0).toUpperCase() + kind.slice(1);
const number = (args.number || '').trim();
const title = (args.title || '').trim();
const color = args.color || 'var(--accent-color)';
const head = `${name}${number ? ' ' + esc(number) : ''}${title ? ' (' + esc(title) + ')' : ''}.`;
const body = (content || '').trim();
const styleKind = /definition|example|remark/.test(kind) ? 'plain' : 'italic';
return `\n\n<div class="mdp-mod-theorem mdp-th-${styleKind}" style="--th-color:${color};"><span class="mdp-th-head">${head}</span> <span class="mdp-th-body">\n\n${body}\n\n</span></div>\n\n`;
